var expect = require('expect.js');
var AuthorizeRange = require('../../res/page/authorizerange/authorizerange');

describe('sqlscan-authorizerange', function(){
  this.timeout(5000);
  before(function(){
    require('./mock-dev-env').mock();
  });
  after(function(){
    require('./mock-dev-env').unmock();
  });
  describe('#init authorizerange()', function(){
    it('init authorizerange', function(done){
      var authorizerange = AuthorizeRange._create({
        record : {
          id : 1,
          status: 0
        },
        events : {
          'afterrender' : function(){
            expect(authorizerange).to.be.ok();
            expect(authorizerange._container).to.be.ok();
            authorizerange._container.on('afterprojectlistload', function(){
              var projectlist = this.query('list[name="projectlist"]');
              expect(projectlist).to.be.ok();
              expect(projectlist.data.records.length).to.be(1);
            });
            authorizerange._container.on('afteruserinfolistload', function(){
              var userlist = this.query('list[name="userlist"]');
              expect(userlist).to.be.ok();
              expect(userlist.data.records.length).to.be(1);
            });
            authorizerange._container.on('aftercomplete', function(){
              done();
            });
          }
        }
      });
    });
  });
  describe('#authorizerange events', function(){
    it('authorizerange events', function(done){
      var authorizerange = AuthorizeRange._create({
        record : {
          id : 1,
          status: 0
        },
        events : {
          'afterrender' : function(){
            var _self = this;
            expect(authorizerange).to.be.ok();
            expect(authorizerange._container).to.be.ok();
            authorizerange._container.on('aftercomplete', function(){
              var projectlist = this.query('list[name="projectlist"]');
              this.on('afteruserinfolistload', function(){
                var userlist = this.query('list[name="userlist"]');
                expect(userlist).to.be.ok();
                expect(userlist.data.records.length).to.be(1);
              });
              projectlist.emit('rowclick', {projectName : 'test'});
              var btnSure = this.query('button[name="btnSure"]');
              btnSure.emit('click');
              done();
            });
          }
        }
      });
    });
  });
});